        {
          id: 'task_001',
          opportunityId: 'opp_001',
          kind: 'collect-evidence',
          status: 'ready'
        },
        {
          id: 'task_002',
          opportunityId: 'opp_001',
          kind: 'score-opportunity',
          status: 'ready'
